import { uuidv7 } from '@motivation/shared';

const KEY_DEVICE_ID = 'client-log.device-id';
const KEY_DEVICE_LABEL = 'client-log.device-label';

interface UserAgentDataLite {
    mobile?: boolean;
    platform?: string;
}

function readUserAgentData(): UserAgentDataLite | null {
    const data = (navigator as Navigator & { userAgentData?: UserAgentDataLite }).userAgentData;
    return data ?? null;
}

function defaultLabel(): string {
    const data = readUserAgentData();
    if (!data) return 'unknown';
    if (data.mobile) return 'phone';
    const platform = (data.platform ?? '').toLowerCase();
    if (platform.includes('linux') || platform.includes('mac') || platform.includes('windows')) {
        return 'desktop';
    }
    return platform || 'desktop';
}

export function getDeviceId(): string {
    const existing = localStorage.getItem(KEY_DEVICE_ID);
    if (existing) return existing;
    const fresh = uuidv7();
    localStorage.setItem(KEY_DEVICE_ID, fresh);
    return fresh;
}

export function getDeviceLabel(): string {
    const existing = localStorage.getItem(KEY_DEVICE_LABEL);
    if (existing) return existing;
    const fresh = defaultLabel();
    localStorage.setItem(KEY_DEVICE_LABEL, fresh);
    return fresh;
}

export function setDeviceLabel(label: string): void {
    const trimmed = label.trim();
    if (!trimmed) throw new Error('device label must not be empty');
    localStorage.setItem(KEY_DEVICE_LABEL, trimmed);
}
